    public NaktamunLorespinner(UUID ownerId, CardSetInfo setInfo) {
        super(ownerId, setInfo, new CardType[]{CardType.CREATURE}, "{2}{R}", "Wheel of Fortune", new CardType[]{CardType.SORCERY}, "{2}{R}");
